import React from "react";

export default function HeroSection({ onOpenDemo }) {
  return (
    <section style={{ padding: 40, background: "#000", color: "white" }}>
      <h1 style={{ fontSize: 44, margin: 0 }}>Pay once. Screen once.</h1>
      <p style={{ opacity: 0.8, maxWidth: 640 }}>
        Built for cinemas, bars, schools and cultural spaces — not for streaming.
      </p>

      <button
        onClick={onOpenDemo}
        style={{
          marginTop: 16,
          padding: "14px 18px",
          borderRadius: 10,
          border: 0,
          background: "#f08a1a",
          color: "white",
          fontWeight: 700,
          cursor: "pointer",
        }}
      >
        ▶ Download Demo Film
      </button>
    </section>
  );
}
